diagram.d2:
direction: right
src: { label: "diagram source\nd2 or mermaid"; class: actor }
conv: { label: "mermaidFlowchartToD2\nmermaid subset -> d2" }
palette: { label: "PALETTE\nD2_CLASS_PRELUDE"; class: store }
render: { label: "renderDiagram\n(the hub)"; class: changed }
d2cli: { label: "d2 CLI"; class: external }
svg: { label: "SVG / <img>" }
excal: { label: "Excalidraw scene\n(editable, opt-in)" }
src -> conv: mermaid
conv -> render: d2 floor
src -> render: d2
palette -> render: prelude + classDefs
render -> d2cli: exec d2
d2cli -> svg: floor SVG
render -> excal: flowchart-class only

diagram.mermaid:
flowchart LR
  src["diagram source d2 or mermaid"] -->|mermaid| conv["mermaidFlowchartToD2"]
  conv -->|d2 floor| render["renderDiagram the hub"]
  src -->|d2| render
  palette["PALETTE prelude + classDefs"] --> render
  render -->|exec d2| d2cli["d2 CLI"]
  d2cli -->|floor SVG| svg["SVG img"]
  render -->|flowchart-class only| excal["Excalidraw scene editable"]
  classDef changed fill:#ffd43b,stroke:#f08c00,color:#1b1b1b,stroke-width:2px;
  classDef actor fill:#d0ebff,stroke:#4dabf7,color:#1b1b1b;
  classDef external fill:#f1f3f5,stroke:#adb5bd,color:#1b1b1b;
  classDef store fill:#e5dbff,stroke:#9775fa,color:#1b1b1b;
  class render changed;
  class src actor;
  class d2cli external;
  class palette store;

diagrams.d2:
direction: right
floor: { label: "d2 compile\n(the floor)"; class: changed }
ok: { label: "SVG" }
ph: { label: "placeholder\n(visible warning)"; class: removed }
eligible: { label: "kind eligible +\nexcalidraw ready?" }
up: { label: "Excalidraw scene\n(editable)"; class: added }
floor -> ok: success
floor -> ph: d2 missing / invalid
ok -> eligible
eligible -> up: yes
eligible -> ok: no / fails -> fall back

diagrams.mermaid:
flowchart LR
  floor["d2 compile the floor"] -->|success| ok["SVG"]
  floor -->|d2 missing or invalid| ph["placeholder visible warning"]
  ok --> eligible["kind eligible + excalidraw ready?"]
  eligible -->|yes| up["Excalidraw scene editable"]
  eligible -->|no or fails| ok
  classDef changed fill:#ffd43b,stroke:#f08c00,color:#1b1b1b,stroke-width:2px;
  classDef added fill:#d3f9d8,stroke:#37b24d,color:#1b1b1b;
  classDef removed fill:#ffe3e3,stroke:#f03e3e,color:#1b1b1b;
  class floor changed;
  class up added;
  class ph removed;
